71	func sanitizeExecuteBeadWorktreeConfig(wtPath string) {
72		for _, key := range []string{"core.bare", "core.worktree"} {
73			_ = internalgit.Command(context.Background(), wtPath, "config", "--worktree", "--unset-all", key).Run()
74		}
75	}
76	
77	func enableExecuteBeadWorktreeConfig(projectRoot string) error {
78		if out, err := internalgit.Command(context.Background(), projectRoot, "config", "extensions.worktreeConfig", "true").CombinedOutput(); err != nil {
79			return fmt.Errorf("enable extensions.worktreeConfig for execute-bead worktree: %s: %w",
80				strings.TrimSpace(string(out)), err)
81		}
82		return nil
83	}
84	
85	func executeBeadWorktreeGitDir(wtPath string) (string, error) {
86		gitMetaPath := filepath.Join(wtPath, ".git")
87		info, err := os.Stat(gitMetaPath)
88		if err != nil {
89			return "", fmt.Errorf("stat worktree .git: %w", err)
90		}
91		if info.IsDir() {
92			return gitMetaPath, nil
93		}
94	
95		raw, err := os.ReadFile(gitMetaPath)
96		if err != nil {
97			return "", fmt.Errorf("read worktree .git file: %w", err)
98		}
99		line := strings.TrimSpace(string(raw))
100		const prefix = "gitdir:"
101		if !strings.HasPrefix(line, prefix) {
102			return "", fmt.Errorf("worktree .git file missing gitdir prefix: %q", line)
103		}
104		gitDir := strings.TrimSpace(strings.TrimPrefix(line, prefix))
105		if !filepath.IsAbs(gitDir) {
106			gitDir = filepath.Clean(filepath.Join(wtPath, gitDir))
107		}
108		return gitDir, nil
109	}
110	
111	func seedExecuteBeadWorktreeConfig(projectRoot, worktreeGitDir string) error {
112		dst := filepath.Join(worktreeGitDir, "config.worktree")
113		if info, err := os.Stat(dst); err == nil && info.Size() > 0 {
114			return nil
115		}
116	
117		commonDirOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--git-common-dir").Output()
118		if err != nil {
119			return fmt.Errorf("locating git common dir for execute-bead: %w", err)
120		}
121		commonDir := strings.TrimSpace(string(commonDirOut))
122		if !filepath.IsAbs(commonDir) {
123			commonDir = filepath.Clean(filepath.Join(projectRoot, commonDir))
124		}
125		src := filepath.Join(commonDir, "config")
126		data, err := os.ReadFile(src)
127		if err != nil {
128			return fmt.Errorf("read shared git config for execute-bead seed: %w", err)
129		}
130		if err := os.WriteFile(dst, data, 0o644); err != nil {
131			return fmt.Errorf("write worktree config seed: %w", err)
132		}
133		return nil
134	}
135	
136	func ensureExecuteBeadPrivateConfig(path string) error {
137		if info, err := os.Stat(path); err == nil && !info.IsDir() {
138			return nil
139		}
140		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
141			return fmt.Errorf("create private git config dir: %w", err)
142		}
143		if err := os.WriteFile(path, []byte{}, 0o644); err != nil {
144			return fmt.Errorf("create private git config: %w", err)
145		}
146		return nil
147	}
148	
149	func renderExecuteBeadGitWrapper(realGit, privateCfg string) string {
150		return fmt.Sprintf(`#!/usr/bin/env bash
151	set -euo pipefail
152	
153	real_git=%q
154	private_cfg=%q
155	
156	args=("$@")
157	sub_idx=-1
158	i=0
159	while (( i < ${#args[@]} )); do
160	  case "${args[$i]}" in
161	    -C|--git-dir|--work-tree|--namespace|--exec-path|--super-prefix|--config-env|-c)
162	      ((i+=2))
163	      continue
164	      ;;
165	    --)
166	      ((i++))
167	      break
168	      ;;
169	    -*)
170	      ((i++))
171	      continue
172	      ;;
173	    *)
174	      sub_idx=$i
175	      break
176	      ;;
177	  esac
178	done
179	
180	if (( sub_idx >= 0 )) && [[ "${args[$sub_idx]}" == "config" ]]; then
181	  prefix=("${args[@]:0:sub_idx}")
182	  suffix=("${args[@]:sub_idx+1}")
183	
184	  repo_scope_idx=-1
185	  explicit_scope=0
186	  dangerous_key=0
187	  for i in "${!suffix[@]}"; do
188	    case "${suffix[$i]}" in
189	      core.bare|core.worktree)
190	        dangerous_key=1
191	        ;;
192	      --local|--worktree)
193	        repo_scope_idx=$i
194	        explicit_scope=1
195	        ;;
196	      --global|--system|--file|--blob)
197	        explicit_scope=1
198	        ;;
199	    esac
200	  done
201	
202	  if (( dangerous_key == 1 )); then
203	    if (( repo_scope_idx >= 0 )); then
204	      suffix[$repo_scope_idx]=--file
205	      suffix=("${suffix[@]:0:repo_scope_idx+1}" "$private_cfg" "${suffix[@]:repo_scope_idx+1}")
206	    elif (( explicit_scope == 0 )); then
207	      suffix=(--file "$private_cfg" "${suffix[@]}")
208	    fi
209	  elif (( repo_scope_idx >= 0 )); then
210	    suffix[$repo_scope_idx]=--worktree
211	  elif (( explicit_scope == 0 )); then
212	    suffix=(--worktree "${suffix[@]}")
213	  fi
214	
215	  exec "$real_git" "${prefix[@]}" config "${suffix[@]}"
216	fi
217	
218	exec "$real_git" "${args[@]}"
219	`, realGit, privateCfg)
220	}
