1	package agent
2	
3	import (
4		"context"
5		"fmt"
6		"os"
7		"path/filepath"
8		"sort"
9		"strings"
10	
11		"github.com/DocumentDrivenDX/ddx/internal/config"
12		internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
13		agentlib "github.com/easel/fizeau"
14	)
15	
16	const (
17		// Lifecycle classifiers run in an isolated scratch workdir and are guarded by
18		// a project-root dirtiness check. Use Fizeau's supported safe permission band
19		// so unpinned auto-routing can choose a route; the reviewer path keeps the
20		// stricter internal readonly marker.
21		PermissionsReadOnlyLifecycle = "safe"
22		lifecycleScratchDirPrefix    = "ddx-lifecycle-"
23	)
24	
25	type lifecycleProjectStatusSnapshot struct {
26		available bool
27		entries   map[string]string
28	}
29	
30	func dispatchLifecycleRun(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
31		scratchDir, err := newLifecycleScratchDir(projectRoot)
32		if err != nil {
33			return nil, fmt.Errorf("lifecycle dispatch: create scratch workdir: %w", err)
34		}
35		defer func() {
36			// Deregister the seeded worktree (no-op/ignored if the fallback empty
37			// repo was used) before removing the directory, so it does not linger
38			// in the project's worktree registry.
39			_ = internalgit.Command(context.Background(), projectRoot, "worktree", "remove", "--force", scratchDir).Run()
40			_ = os.RemoveAll(scratchDir)
41		}()
42	
43		runtime.WorkDir = scratchDir
44		runtime.PermissionsOverride = PermissionsReadOnlyLifecycle
45	
46		before, err := captureLifecycleProjectStatus(projectRoot)
47		if err != nil {
48			return nil, err
49		}
50	
51		result, dispatchErr := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)
52	
53		if guardErr := guardLifecycleProjectStatus(projectRoot, before); guardErr != nil {
54			return nil, guardErr
55		}
56		if dispatchErr != nil {
57			return nil, dispatchErr
58		}
59		return result, nil
60	}
61	
62	func newLifecycleScratchDir(projectRoot string) (string, error) {
63		dir, err := config.MkdirExecutionScratch(projectRoot, lifecycleScratchDirPrefix)
64		if err != nil {
65			return "", err
66		}
67		// Seed the scratch workdir from the project's HEAD so the readiness-check
68		// classifier sees the project's real source files rather than an empty repo
69		// — otherwise file-presence checks block every bead (ddx-efadca32). A
70		// detached worktree keeps the classifier isolated from the master worktree
71		// (it cannot mutate tracked files there). git worktree add must create the
72		// directory itself, so clear the placeholder MkdirExecutionScratch made.
73		if rmErr := os.RemoveAll(dir); rmErr != nil {
74			return "", fmt.Errorf("reset lifecycle scratch dir: %w", rmErr)
75		}
76		if out, addErr := internalgit.Command(context.Background(), projectRoot, "worktree", "add", "--detach", dir, "HEAD").CombinedOutput(); addErr != nil {
77			// HEAD may be unborn (a project with no commits yet); readiness has
78			// nothing to check there, so fall back to an empty scratch repo.
79			if mkErr := os.MkdirAll(dir, 0o700); mkErr != nil {
80				return "", fmt.Errorf("recreate lifecycle scratch dir after worktree add failed (%s): %w", strings.TrimSpace(string(out)), mkErr)
81			}
82			if out2, initErr := internalgit.Command(context.Background(), dir, "init", "-q").CombinedOutput(); initErr != nil {
83				_ = os.RemoveAll(dir)
84				return "", fmt.Errorf("initialize lifecycle scratch git repo: %s: %w", strings.TrimSpace(string(out2)), initErr)
85			}
86		}
87		return dir, nil
88	}
89	
90	func captureLifecycleProjectStatus(projectRoot string) (lifecycleProjectStatusSnapshot, error) {
91		if strings.TrimSpace(projectRoot) == "" {
92			return lifecycleProjectStatusSnapshot{}, nil
93		}
94		if _, err := os.Stat(filepath.Join(projectRoot, ".git")); err != nil {
95			if os.IsNotExist(err) {
96				return lifecycleProjectStatusSnapshot{}, nil
97			}
98			return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: stat project root .git: %w", err)
99		}
100		out, err := internalgit.Command(context.Background(), projectRoot, "status", "--porcelain", "--untracked-files=all").Output()
101		if err != nil {
102			return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: snapshot project root dirtiness: %w", err)
103		}
104		return lifecycleProjectStatusSnapshot{
105			available: true,
106			entries:   parseLifecycleProjectStatus(string(out)),
107		}, nil
108	}
109	
110	func parseLifecycleProjectStatus(raw string) map[string]string {
111		entries := map[string]string{}
112		for _, line := range strings.Split(raw, "\n") {
113			line = strings.TrimRight(line, "\r")
114			if len(line) < 4 || strings.TrimSpace(line) == "" {
115				continue
116			}
117			status := line[:2]
118			path := strings.TrimSpace(line[3:])
119			if idx := strings.Index(path, " -> "); idx >= 0 {
120				path = strings.TrimSpace(path[idx+4:])
121			}
122			if path == "" {
123				continue
124			}
125			entries[path] = status
126		}
127		return entries
128	}
129	
130	func guardLifecycleProjectStatus(projectRoot string, before lifecycleProjectStatusSnapshot) error {
131		if !before.available {
132			return nil
133		}
134		after, err := captureLifecycleProjectStatus(projectRoot)
135		if err != nil {
136			return err
137		}
138		if lifecycleProjectStatusEqual(before.entries, after.entries) {
139			return nil
140		}
141	
142		newPaths, changedPaths := diffLifecycleProjectStatus(before.entries, after.entries)
143		if len(newPaths) > 0 {
144			if err := restoreLifecycleProjectMutations(projectRoot, after.entries, newPaths); err != nil {
145				return err
146			}
147			restored, restoreErr := captureLifecycleProjectStatus(projectRoot)
148			if restoreErr != nil {
149				return restoreErr
150			}
151			after = restored
152			newPaths, changedPaths = diffLifecycleProjectStatus(before.entries, after.entries)
153		}
154		if len(newPaths) == 0 && len(changedPaths) == 0 {
155			return fmt.Errorf("lifecycle dispatch: project root mutation rejected")
156		}
157	
158		var details []string
159		if len(newPaths) > 0 {
160			details = append(details, "new dirty paths: "+strings.Join(newPaths, ", "))
161		}
162		if len(changedPaths) > 0 {
163			details = append(details, "changed existing dirty paths: "+strings.Join(changedPaths, ", "))
164		}
165		return fmt.Errorf("lifecycle dispatch: project root mutation rejected (%s)", strings.Join(details, "; "))
166	}
167	
168	func lifecycleProjectStatusEqual(left, right map[string]string) bool {
169		if len(left) != len(right) {
170			return false
171		}
172		for path, status := range left {
173			if right[path] != status {
174				return false
175			}
176		}
177		return true
178	}
179	
180	func diffLifecycleProjectStatus(before, after map[string]string) (newPaths []string, changedPaths []string) {
181		for path, afterStatus := range after {
182			beforeStatus, ok := before[path]
183			if !ok {
184				newPaths = append(newPaths, path)
185				continue
186			}
187			if beforeStatus != afterStatus {
188				changedPaths = append(changedPaths, path)
189			}
190		}
191		for path := range before {
192			if _, ok := after[path]; !ok {
193				changedPaths = append(changedPaths, path)
194			}
195		}
196		sort.Strings(newPaths)
197		sort.Strings(changedPaths)
198		return newPaths, changedPaths
199	}
200	
201	func restoreLifecycleProjectMutations(projectRoot string, after map[string]string, newPaths []string) error {
202		var restorePaths []string
203		var cleanPaths []string
204		for _, path := range newPaths {
205			if after[path] == "??" {
206				cleanPaths = append(cleanPaths, path)
207				continue
208			}
209			restorePaths = append(restorePaths, path)
210		}
211	
212		if len(restorePaths) > 0 {
213			args := []string{"restore", "--source=HEAD", "--staged", "--worktree", "--"}
214			args = append(args, restorePaths...)
215			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
216				return fmt.Errorf("lifecycle dispatch: restore project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
217			}
218		}
219		if len(cleanPaths) > 0 {
220			args := []string{"clean", "-fd", "--"}
221			args = append(args, cleanPaths...)
222			if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
223				return fmt.Errorf("lifecycle dispatch: clean project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
224			}
225		}
226		return nil
227	}
