1	// Package escalation implements a MinPower-only escalation ladder used by
2	// the execute-bead loop to pick the next power floor after a substantive
3	// failure. The ladder reasons about Power values only — it never inspects
4	// provider names, model IDs, harness names, or any other vendor-identifying
5	// attributes. This keeps escalation portable across catalogs that disagree
6	// on which vendor sits at which powerClass.
7	package escalation
8	
9	import (
10		"errors"
11		"fmt"
12		"sort"
13	
14		agentlib "github.com/easel/fizeau"
15	)
16	
17	// ErrLadderExhausted is returned by Ladder.Next when no power powerClass above
18	// the supplied actualPower exists in the catalog. Power escalation cannot
19	// proceed any further at this catalog.
20	var ErrLadderExhausted = errors.New("escalation: ladder exhausted; no higher power powerClass in catalog")
21	
22	// NoViableProviderError signals that the next catalog powerClass above the
23	// caller's actualPower has no viable provider — i.e., every model at that
24	// powerClass is either unavailable or not auto-routable. The loop bumps further
25	// by calling Next(Floor) to skip past this dead powerClass.
26	type NoViableProviderError struct {
27		// Floor is the catalog power powerClass that was skipped because it had no
28		// viable provider. Pass this value back into Next() to bump further.
29		Floor int
30	}
31	
32	func (e *NoViableProviderError) Error() string {
33		return fmt.Sprintf("escalation: no viable provider at floor %d", e.Floor)
34	}
35	
36	// Ladder is a MinPower-only escalation ladder. It enumerates the distinct
37	// power powerClasses present in a fizeau model listing, sorted ascending, and tracks
38	// which powerClasses have at least one viable model.
39	type Ladder struct {
40		powerClasses []int
41		viableSet    map[int]struct{}
42	}
43	
44	// NewLadder constructs a Ladder from fizeau model metadata. Models with Power<=0
45	// are ignored as unrated. A model contributes to the viable set when it is
46	// both Available and AutoRoutable; non-viable powerClasses remain present in the
47	// ladder so Next can report a typed NoViableProviderError when one is hit.
48	func NewLadder(models []agentlib.ModelInfo) *Ladder {
49		seen := map[int]struct{}{}
50		viable := map[int]struct{}{}
51		for _, m := range models {
52			if m.Power <= 0 {
53				continue
54			}
55			seen[m.Power] = struct{}{}
56			if m.Available && m.AutoRoutable {
57				viable[m.Power] = struct{}{}
58			}
59		}
60		powerClasses := make([]int, 0, len(seen))
61		for p := range seen {
62			powerClasses = append(powerClasses, p)
63		}
64		sort.Ints(powerClasses)
65		return &Ladder{powerClasses: powerClasses, viableSet: viable}
66	}
67	
68	// PowerClasses returns the distinct catalog power powerClasses, ascending. The returned
69	// slice is a copy.
70	func (l *Ladder) PowerClasses() []int {
71		if l == nil {
72			return nil
73		}
74		out := make([]int, len(l.powerClasses))
75		copy(out, l.powerClasses)
76		return out
77	}
78	
79	// Next returns the next power floor strictly greater than actualPower.
80	//
81	// actualPower is sourced from the previous attempt's routing-actual record
82	// (RoutingActual.Power). The escalation loop calls Next(actualPower) after
83	// a substantive failure to obtain the floor for the next attempt.
84	//
85	// Three outcomes:
86	//
87	//   - The next catalog powerClass above actualPower has at least one viable
88	//     model: returns (floor, nil).
89	//   - The next catalog powerClass above actualPower has no viable provider:
90	//     returns (0, *NoViableProviderError{Floor: powerClass}). The loop bumps
91	//     further by calling Next(powerClass).
92	//   - No catalog powerClass above actualPower exists: returns (0, ErrLadderExhausted).
93	func (l *Ladder) Next(actualPower int) (int, error) {
94		if l == nil || len(l.powerClasses) == 0 {
95			return 0, ErrLadderExhausted
96		}
97		for _, t := range l.powerClasses {
98			if t <= actualPower {
99				continue
100			}
101			if _, ok := l.viableSet[t]; !ok {
102				return 0, &NoViableProviderError{Floor: t}
103			}
104			return t, nil
105		}
106		return 0, ErrLadderExhausted
107	}
