400	func checkTreeClean(ctx context.Context, projectRoot, beadID string) error {
401		out, err := internalgit.Command(ctx, projectRoot, "status", "--porcelain").Output()
402		if err != nil {
403			return fmt.Errorf("checking git status: %w", err)
404		}
405	
406		var dirtyFiles []string
407		for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
408			if line == "" {
409				continue
410			}
411			path := strings.TrimSpace(line[3:])
412			if path == "" {
413				continue
414			}
415			if strings.HasPrefix(path, ".ddx") || strings.HasPrefix(path, ExecuteBeadArtifactDir) {
416				continue
417			}
418			dirtyFiles = append(dirtyFiles, path)
419		}
420	
421		if len(dirtyFiles) > 0 {
422			return fmt.Errorf("working tree is not clean; modified files:\n%s", strings.Join(dirtyFiles, "\n"))
423		}
424		return nil
425	}
