input.new_string:
// TestLoop_WatchCheckpointDirtyChurnEscalatesToOperatorAttention reproduces a
// HELIX-style churn loop: the project root keeps producing uncommitted
// implementation changes, so every dispatch hits the pre-dispatch checkpoint
// refusal even though each preservation succeeds. Without the churn guard the
// watch loop would preserve-and-redispatch forever. The guard bounds consecutive
// preservations to PreDispatchDirtyChurnThreshold and then escalates the dirty
// root to operator attention so the churn stops (ddx-24ebc57a).
func TestLoop_WatchCheckpointDirtyChurnEscalatesToOperatorAttention(t *testing.T) {
	inner, first, second := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	dirtyPaths := []string{"cli/internal/agent/dirty_impl.go"}
	var preserveCalls int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			// The churning root re-dirties the same implementation file before
			// every dispatch, so the checkpoint refuses on each attempt.
			return ExecuteBeadReport{}, fmt.Errorf(
				"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
				preExecuteCheckpointDirtyMarker,
				strings.Join(dirtyPaths, ", "),
			)
		}),
		preDispatchDirtyPreserver: func(projectRoot string, paths []string) (*PreDispatchDirtyPreservation, error) {
			n := atomic.AddInt32(&preserveCalls, 1)
			return &PreDispatchDirtyPreservation{
				DirtyPaths:     append([]string(nil), paths...),
				PreserveRef:    fmt.Sprintf("refs/ddx/pre-dispatch/churn-%d", n),
				RecoverCommand: fmt.Sprintf("git stash apply refs/ddx/pre-dispatch/churn-%d", n),
			}, nil
		},
	}

	const churnThreshold = 2
	var logBuf, eventSink bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	// The timeout is a regression net: if the churn guard ever fails the loop
	// preserves forever and the deadline trips instead of returning cleanly.
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                           executeloop.ModeWatch,
		IdleInterval:                   time.Hour,
		Log:                            &logBuf,
		WakeCh:                         make(chan struct{}),
		EventSink:                      &eventSink,
		ProjectRoot:                    "/repo/churn",
		SessionID:                      "sess-churn",
		WorkerID:                       "worker-churn",
		PreDispatchDirtyChurnThreshold: churnThreshold,
	})

	require.NoError(t, err, "the churn guard must stop the loop, not let the deadline trip")
	require.NotNil(t, result)
	assert.Equal(t, int32(churnThreshold), atomic.LoadInt32(&preserveCalls),
		"the loop must preserve exactly the churn threshold before escalating")
	assert.Equal(t, int32(churnThreshold+1), atomic.LoadInt32(&store.claimCalls),
		"the churning bead is reclaimed once per preservation plus the escalating dispatch")

	assert.Equal(t, "OperatorAttention", result.StopCondition)
	assert.Equal(t, "operator_attention", result.ExitReason)
	require.NotNil(t, result.OperatorAttention)
	assert.Equal(t, preDispatchDirtyChurnReason, result.OperatorAttention.Reason)
	assert.Equal(t, first.ID, result.OperatorAttention.BeadID)
	assert.Equal(t, "/repo/churn", result.OperatorAttention.ProjectRoot)
	assert.Equal(t, dirtyPaths, result.OperatorAttention.DirtyPaths)
	assert.Contains(t, result.OperatorAttention.Message, "churn loop")

	gotFirst, err := store.Get(first.ID)
	require.NoError(t, err)
	gotSecond, err := store.Get(second.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, gotFirst.Status)
	assert.Equal(t, bead.StatusOpen, gotSecond.Status)
	assert.Empty(t, gotFirst.Owner)
	assert.Empty(t, gotSecond.Owner, "the churn stop must not bleed into other ready beads")

	out := logBuf.String()
	assert.Contains(t, out, "operator attention")
	assert.Contains(t, out, "churn loop")

	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var preservedEvents int
	var churnAttention map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		switch entry["type"] {
		case "loop.pre_dispatch_dirty_preserved":
			preservedEvents++
		case "loop.operator_attention":
			data, ok := entry["data"].(map[string]any)
			require.True(t, ok, "loop.operator_attention must include data")
			churnAttention = data
		}
	}
	assert.Equal(t, churnThreshold, preservedEvents,
		"one preservation event per bounded preservation")
	require.NotNil(t, churnAttention, "the churn stop must emit loop.operator_attention")
	assert.Equal(t, preDispatchDirtyChurnReason, churnAttention["reason"])
}

